local UITowerDefenseWaitTip = class("UITowerDefenseWaitTip", IGUILayout)

function UITowerDefenseWaitTip:onLoad()

    self.TowerDefenseWaitTip = self:getChildWindow("TowerDefenseWaitTip", GUIType.Layout)

    self.TowerDefenseWaitTip:SetAlwaysOnTop(true)

    self.readyIcon = self:getChildWindow("TowerDefenseWaitTip_ready", GUIType.StaticImage)
    self.waitCountdown = self:getChildWindow("TowerDefenseWaitTip_wait_countdown", GUIType.StaticImage)

    self.tipMessage = self:getChildWindow("TowerDefenseWaitTipMessage", GUIType.StaticText)
    self.teamRemain = self:getChildWindow("TowerDefenseWaitTip_person_text", GUIType.StaticText)

    self:registerDataCallBack("WaitTip", function(data)
        local countdown = tonumber(data:getParam("countdown"))
        local type = tonumber(data:getParam("type"))
        local currentTeammateNum = data:getParam("currentTeammateNum")
        local allTeammateNum = data:getParam("allTeammateNum")
        self:showWaitTip(type, countdown, currentTeammateNum, allTeammateNum)
    end, DataBuilderProcessor)
end

function UITowerDefenseWaitTip:showWaitTip(type, countdown, currentTeammateNum, allTeammateNum)

    if type == Define.WaitMessageType.StartShow then
        GUIWaitTip.TowerDefenseWaitTip:SetYPosition({ 0, 0 })
        self.waitCountdown:SetVisible(true)
        self.readyIcon:SetVisible(false)

        self.tipMessage:SetText(Lang:getString("gui_TowerDefenseWaitTip_OnWait"))
        self.teamRemain:SetText("")

        self.teamRemain:SetText(currentTeammateNum .. "/" .. allTeammateNum)

        local curSec = countdown
        GUINumberItem.setNumberToLayout(curSec, self.waitCountdown, true)
        LuaTimer:scheduleTimer(function()
            curSec = curSec - 1
            GUINumberItem.setNumberToLayout(curSec, self.waitCountdown, true)
        end, 1000, countdown)

    elseif type == Define.WaitMessageType.Update then

        self.teamRemain:SetText(currentTeammateNum .. "/" .. allTeammateNum)

    elseif type == Define.WaitMessageType.OnBegin then

        self.waitCountdown:SetVisible(false)
        self.readyIcon:SetVisible(true)
        self.teamRemain:SetText(currentTeammateNum .. "/" .. allTeammateNum)
        self.tipMessage:SetText(Lang:getString("gui_TowerDefenseWaitTip_OnBegin"))

    elseif type == Define.WaitMessageType.Close then

        LuaTimer:scheduleTimer(function()
            local yPos = GUIWaitTip.TowerDefenseWaitTip:GetYPosition()
            yPos[1] = yPos[1] - 0.2
            GUIWaitTip.TowerDefenseWaitTip:SetYPosition(yPos)
        end, 10, 20)

    end
    self:show()
end

return UITowerDefenseWaitTip